class Solution:
    def minimumArrayLength(self, nums: list) -> int:
        m = min(nums)
        cnt = nums.count(m)
        # Check if any element is not divisible by min
        if any(x % m != 0 for x in nums):
            return 1
        # All divisible by m: only copies of m survive
        return (cnt + 1) // 2

