solutions.javascript:
var minimumArrayLength = function(nums) {
    const m = Math.min(...nums);
    let cnt = 0;
    let allDiv = true;
    for (const x of nums) {
        if (x === m) cnt++;
        if (x % m !== 0) allDiv = false;
    }
    if (!allDiv) return 1;
    return Math.floor((cnt + 1) / 2);
};
